// SuccessStories.jsx
import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { successStories, platformStats } from '../data/talentData';
import './SuccessStories.css';

function StoryCard({ story, onOpen }) {
  const { name, initials, avatarColor, role, company, companyLogo,
          companyColor, college, tagColor, stipend, ppo, quote,
          timeToOffer, year, skills } = story;

  const colorMap = {
    lavender: { accent: '#C4B5FD', dim: 'rgba(196,181,253,0.12)' },
    mint:     { accent: '#86EFAC', dim: 'rgba(134,239,172,0.12)' },
    peach:    { accent: '#FCA5A5', dim: 'rgba(252,165,165,0.12)' },
    cyan:     { accent: '#67E8F9', dim: 'rgba(103,232,249,0.12)' },
    amber:    { accent: '#FCD34D', dim: 'rgba(252,211,77,0.12)'  },
  };
  const colors = colorMap[tagColor] || colorMap.lavender;

  return (
    <div className="story-card" onClick={() => onOpen(story)}>
      {/* Quote mark */}
      <div className="story-card__quote-mark" style={{ color: colors.accent }}>"</div>

      <p className="story-card__quote">{quote}</p>

      {/* Skills */}
      <div className="story-card__skills">
        {skills.map(s => (
          <span key={s} className="story-card__skill" style={{ background: colors.dim, color: colors.accent }}>
            {s}
          </span>
        ))}
      </div>

      {/* Footer */}
      <div className="story-card__footer">
        <div className="story-card__person">
          <div
            className="story-card__avatar"
            style={{ background: colors.dim, color: colors.accent, borderColor: colors.accent }}
          >
            {initials}
          </div>
          <div>
            <span className="story-card__name">{name}</span>
            <span className="story-card__meta">{role}</span>
            <span className="story-card__college">{college}</span>
          </div>
        </div>

        <div className="story-card__company">
          <div
            className="story-card__company-logo"
            style={{ color: companyColor, background: `${companyColor}18` }}
          >
            {companyLogo}
          </div>
          <span className="story-card__company-name">{company}</span>
        </div>
      </div>

      {/* Badges */}
      <div className="story-card__badges">
        <span className="story-card__badge story-card__badge--stipend">💰 {stipend}</span>
        <span className="story-card__badge story-card__badge--time">⚡ Offer in {timeToOffer}</span>
        {ppo && <span className="story-card__badge story-card__badge--ppo">🎯 PPO Received</span>}
      </div>
    </div>
  );
}

function StoryModal({ story, onClose }) {
  const [expanded, setExpanded] = useState(false);

  if (!story) return null;

  const { name, initials, avatarColor, role, company, companyLogo,
          companyColor, college, tagColor, stipend, ppo, quote,
          timeToOffer, year, skills, domain } = story;

  const colorMap = {
    lavender: { accent: '#C4B5FD', dim: 'rgba(196,181,253,0.12)' },
    mint:     { accent: '#86EFAC', dim: 'rgba(134,239,172,0.12)' },
    peach:    { accent: '#FCA5A5', dim: 'rgba(252,165,165,0.12)' },
    cyan:     { accent: '#67E8F9', dim: 'rgba(103,232,249,0.12)' },
    amber:    { accent: '#FCD34D', dim: 'rgba(252,211,77,0.12)'  },
  };
  const colors = colorMap[tagColor] || colorMap.lavender;

  const journey = [
    { step: 'Profile Created', detail: 'Uploaded resume, listed skills & projects', done: true },
    { step: 'Matched by AI', detail: `Launchpad surfaced ${company} as a top match`, done: true },
    { step: 'Applied', detail: '1-click application with profile match score', done: true },
    { step: 'Interview Scheduled', detail: 'Heard back within ' + timeToOffer, done: true },
    { step: 'Offer Received', detail: stipend + (ppo ? ' + PPO' : ''), done: true },
  ];

  return (
    <div className="story-modal-overlay" onClick={onClose}>
      <div className="story-modal-panel page-enter" onClick={e => e.stopPropagation()}>
        <button className="story-modal-close" onClick={onClose}>✕</button>

        <div className="story-modal-header" style={{ '--acc': colors.accent }}>
          <div className="story-modal-header__glow" />
          <div className="story-modal-header__top">
            <div className="story-modal-avatar" style={{ background: colors.dim, color: colors.accent, borderColor: colors.accent }}>
              {initials}
            </div>
            <div>
              <h2 className="story-modal-name">{name}</h2>
              <p className="story-modal-role">{role} @ {company}</p>
              <p className="story-modal-college">{college}</p>
            </div>
            <div className="story-modal-company">
              <div className="story-modal-company-logo" style={{ color: companyColor, background: `${companyColor}18` }}>
                {companyLogo}
              </div>
            </div>
          </div>
        </div>

        <div className="story-modal-body">
          {/* Quote */}
          <div className="story-modal-quote">
            <span className="story-modal-quote-mark" style={{ color: colors.accent }}>"</span>
            <p>{quote}</p>
          </div>

          {/* Stats */}
          <div className="story-modal-stats">
            {[
              { icon: '💰', label: 'Stipend', val: stipend },
              { icon: '⚡', label: 'Time to offer', val: timeToOffer },
              { icon: '🎓', label: 'Type', val: ppo ? 'Internship + PPO' : 'Internship' },
              { icon: '📅', label: 'Year', val: year },
            ].map(s => (
              <div key={s.label} className="story-modal-stat">
                <span className="story-modal-stat__icon">{s.icon}</span>
                <span className="story-modal-stat__val" style={{ color: colors.accent }}>{s.val}</span>
                <span className="story-modal-stat__label">{s.label}</span>
              </div>
            ))}
          </div>

          {/* Skills */}
          <div className="story-modal-section">
            <h4 className="story-modal-section-title">Skills Used</h4>
            <div className="story-modal-skills">
              {skills.map(s => (
                <span key={s} className="story-modal-skill" style={{ background: colors.dim, color: colors.accent }}>
                  {s}
                </span>
              ))}
            </div>
          </div>

          {/* Journey */}
          <div className="story-modal-section">
            <h4 className="story-modal-section-title">Their Journey on Launchpad</h4>
            <div className="story-modal-journey">
              {journey.map((j, i) => (
                <div key={j.step} className="story-modal-step">
                  <div className="story-modal-step__dot" style={{ background: colors.accent }} />
                  {i < journey.length - 1 && <div className="story-modal-step__line" />}
                  <div className="story-modal-step__content">
                    <span className="story-modal-step__title">{j.step}</span>
                    <span className="story-modal-step__detail">{j.detail}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <Link to="/register" className="btn btn-primary btn-lg story-modal-cta">
            🚀 Start Your Own Story
          </Link>
        </div>
      </div>
    </div>
  );
}

export default function SuccessStories() {
  const [activeStory, setActiveStory] = useState(null);
  const [filter, setFilter] = useState('All');
  const domains = ['All', 'Engineering', 'Data Science', 'Design', 'Marketing'];

  const filtered = filter === 'All'
    ? successStories
    : successStories.filter(s => s.domain === filter);

  return (
    <div className="stories-page page-enter">
      {activeStory && <StoryModal story={activeStory} onClose={() => setActiveStory(null)} />}

      {/* ── HERO ── */}
      <section className="stories-hero">
        <div className="stories-hero__orb stories-hero__orb--1" />
        <div className="stories-hero__orb stories-hero__orb--2" />

        <div className="container stories-hero__content">
          <div className="section-label">Real People, Real Results</div>
          <h1 className="stories-hero__headline">
            Success Stories
          </h1>
          <p className="stories-hero__sub">
            From zero experience to dream internships — hear directly from students
            who launched their careers through Launchpad.
          </p>
        </div>

        {/* Platform stats band */}
        <div className="stories-stats-band">
          <div className="container stories-stats-band__inner">
            {platformStats.map(s => (
              <div key={s.label} className="stories-stat">
                <span className="stories-stat__val">{s.value}</span>
                <span className="stories-stat__label">{s.label}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── STORIES GRID ── */}
      <section className="stories-grid-section">
        <div className="container">
          {/* Filter tabs */}
          <div className="stories-filters">
            {domains.map(d => (
              <button
                key={d}
                className={`stories-filter-tab ${filter === d ? 'active' : ''}`}
                onClick={() => setFilter(d)}
              >
                {d}
              </button>
            ))}
          </div>

          <div className="stories-grid">
            {filtered.map((story, i) => (
              <StoryCard
                key={story.id}
                story={story}
                onOpen={setActiveStory}
              />
            ))}
          </div>

          {/* CTA banner */}
          <div className="stories-cta-banner">
            <div className="stories-cta-banner__orb" />
            <div className="stories-cta-banner__content">
              <h2>Ready to write your story?</h2>
              <p>Join 8,50,000+ students who found their opportunity on Launchpad. It's free.</p>
              <div className="stories-cta-banner__btns">
                <Link to="/register" className="btn btn-primary btn-lg">🎓 Create Free Account</Link>
                <Link to="/internships" className="btn btn-secondary btn-lg">Browse Internships</Link>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}
